export function useT() {
  const [lang, setLang] = useState(localStorage.getItem('pg_lang') || 'en')
  useEffect(() => {
    const handler = () => setLang(localStorage.getItem('pg_lang') || 'en')
    window.addEventListener('pg_lang_change', handler)
    return () => window.removeEventListener('pg_lang_change', handler)
  }, [])
  return (key) => (TRANSLATIONS[lang]?.[key]) ?? (TRANSLATIONS.en[key]) ?? key
}

export function getLang() {
  return localStorage.getItem('pg_lang') || 'en'
}
